import React, {useEffect, useState} from 'react';
import axios from 'axios';

export default function History({limit=50, onReplay}){
  const [items,setItems] = useState([]);
  const [loading,setLoading] = useState(false);
  const [filter,setFilter] = useState('');

  useEffect(()=>{ fetchHistory(); },[]);

  async function fetchHistory(){
    setLoading(true);
    try{
      const res = await axios.get(`/api/history?limit=${limit}`);
      setItems(res.data.items || []);
    }catch(e){
      console.error('Failed to load history', e);
    }finally{ setLoading(false); }
  }

  const shown = items.filter(it => {
    if(!filter) return true;
    const f = filter.toLowerCase();
    return (it.user_message || '').toLowerCase().includes(f) || (it.assistant_reply || '').toLowerCase().includes(f);
  });

  return (
    <div style={{padding:12}}>
      <h3>Conversation History</h3>
      <div style={{marginBottom:8}}>
        <input placeholder="Search history..." value={filter} onChange={e=>setFilter(e.target.value)} style={{width:'100%'}} />
      </div>
      {loading && <div>Loading...</div>}
      {!loading && items.length === 0 && <div>No history yet.</div>}
      <div style={{maxHeight:500,overflow:'auto'}}>
        {shown.map(it=> (
          <div key={it.id} style={{padding:8,borderBottom:'1px solid #eee',cursor:'pointer'}} onClick={()=> onReplay && onReplay(it.user_message, it.assistant_reply)}>
            <div style={{fontSize:12,color:'#666'}}>{new Date(it.created_at).toLocaleString()}</div>
            <div><strong>User:</strong> {it.user_message}</div>
            <div><strong>Assistant:</strong> {it.assistant_reply}</div>
            {it.redflag && <div style={{color:'orange'}}>Red-flag: {it.redflag_details}</div>}
          </div>
        ))}
      </div>
    </div>
  )
}
